class TreeNode<T> {
  constructor(
    public value: T,
    public left: TreeNode<T> | null = null,
    public right: TreeNode<T> | null = null
  ) {}
}

class BST<T> {
  private root: TreeNode<T> | null = null;

  insert(value: T): void {
    const node = new TreeNode(value);
    if (this.root === null) {
      this.root = node;
      return;
    }
    let current = this.root;
    while (true) {
      if (value < current.value) {
        if (current.left === null) {
          current.left = node;
          return;
        }
        current = current.left;
      } else {
        if (current.right === null) {
          current.right = node;
          return;
        }
        current = current.right;
      }
    }
  }
}

class BST<T> implements Iterable<T> {
  private root: TreeNode<T> | null = null;

  // ... insert ...

  private *inOrder(node: TreeNode<T> | null): Generator<T> {
    if (node === null) return;
    yield* this.inOrder(node.left);   // Обход левого поддерева
    yield node.value;                  // Текущий узел
    yield* this.inOrder(node.right);  // Обход правого поддерева
  }

  [Symbol.iterator](): Iterator<T> {
    return this.inOrder(this.root);
  }
}

