function* filter<T>(
  iterable: Iterable<T>,
  predicate: (item: T) => boolean
): Generator<T> {
  for (const item of iterable) {
    if (predicate(item)) yield item;
  }
}

const tree = new BST<number>();
[5, 3, 7, 1, 4, 8, 2].forEach((n) => tree.insert(n));

// Ленивая фильтрация: чётные элементы дерева
const evens = [...filter(tree, (n) => n % 2 === 0)];
console.log(evens); // [2, 4, 8]
